import { mergeSorted } from '../../src/merge.mjs';
import test from 'node:test';
import assert from 'node:assert';
test('golden merge', () => {
  assert.deepStrictEqual(mergeSorted([], [1, 2]), [1, 2]);
  assert.deepStrictEqual(mergeSorted([1, 4, 5], [2, 3, 6]), [1, 2, 3, 4, 5, 6]);
  assert.deepStrictEqual(mergeSorted([1, 2], [2, 3]), [1, 2, 2, 3]);
  assert.strictEqual(mergeSorted([1, 2, 3], [4, 5]).length, 5);
});
